select
    id, condition_label, bearing_code, sample_no, file_name, source_file, file_size, data_usage,
    aircraft_id, subsystem_id, equipment_id, component_id, create_time
from fault_iden_sample
where condition_label = #{conditionLabel}
  and bearing_code = #{bearingCode}
  and file_name = #{fileName}

  and data_usage = #{dataUsage}

limit 1

select
    id, condition_label, bearing_code, sample_no, file_name, source_file, file_size, data_usage,
    aircraft_id, subsystem_id, equipment_id, component_id, create_time
from fault_iden_sample
where condition_label = #{conditionLabel}
  and bearing_code = #{bearingCode}

  and data_usage = #{dataUsage}


  and source_file like concat('%', #{uploadBatchId}, '%')


  and file_name like concat('%', #{keyword}, '%')

order by sample_no

    limit #{pageSize}

        offset #{offset}

select id, condition_label, bearing_code, sample_no, file_name, source_file, file_size, data_usage, aircraft_id, subsystem_id, equipment_id, component_id, create_time from fault_iden_sample where id in
#{id}
and data_usage = #{dataUsage}
order by condition_label, bearing_code, sample_no

select id, condition_label, bearing_code, sample_no, file_name, source_file, file_size, data_usage, aircraft_id, subsystem_id, equipment_id, component_id, create_time from fault_iden_sample where 1 = 1
and data_usage = #{dataUsage}
and source_file like concat('%', #{uploadBatchId}, '%')
and ( file_name like concat('%', #{keyword}, '%') or source_file like concat('%', #{keyword}, '%') or condition_label like concat('%', #{keyword}, '%') or bearing_code like concat('%', #{keyword}, '%') )
order by create_time desc, id desc
limit #{pageSize}
offset #{offset}

